@Override
        public Calendar read(JsonReader in) throws IOException {
          if (in.peek() == JsonToken.NULL) {
            in.nextNull();
            return null;
          }
          in.beginObject();
          int year = 0;
          int month = 0;
          int dayOfMonth = 0;
          int hourOfDay = 0;
          int minute = 0;
          int second = 0;
          while (in.peek() != JsonToken.END_OBJECT) {
            String name = in.nextName();
            int value = in.nextInt();
            switch (name) {
              case YEAR:
                year = value;
                break;
              case MONTH:
                month = value;
                break;
              case DAY_OF_MONTH:
                dayOfMonth = value;
                break;
              case HOUR_OF_DAY:
                hourOfDay = value;
                break;
              case MINUTE:
                minute = value;
                break;
              case SECOND:
                second = value;
                break;
              default:
                // Ignore unknown JSON property
            }
          }
          in.endObject();
          return new GregorianCalendar(year, month, dayOfMonth, hourOfDay, minute, second);
        }

@Override
        public void write(JsonWriter out, Calendar value) throws IOException {
          if (value == null) {
            out.nullValue();
            return;
          }
          out.beginObject();
          out.name(YEAR);
          out.value(value.get(Calendar.YEAR));
          out.name(MONTH);
          out.value(value.get(Calendar.MONTH));
          out.name(DAY_OF_MONTH);
          out.value(value.get(Calendar.DAY_OF_MONTH));
          out.name(HOUR_OF_DAY);
          out.value(value.get(Calendar.HOUR_OF_DAY));
          out.name(MINUTE);
          out.value(value.get(Calendar.MINUTE));
          out.name(SECOND);
          out.value(value.get(Calendar.SECOND));
          out.endObject();
        }

@Override
        public Locale read(JsonReader in) throws IOException {
          if (in.peek() == JsonToken.NULL) {
            in.nextNull();
            return null;
          }
          String locale = in.nextString();
          StringTokenizer tokenizer = new StringTokenizer(locale, "_");
          String language = null;
          String country = null;
          String variant = null;
          if (tokenizer.hasMoreElements()) {
            language = tokenizer.nextToken();
          }
          if (tokenizer.hasMoreElements()) {
            country = tokenizer.nextToken();
          }
          if (tokenizer.hasMoreElements()) {
            variant = tokenizer.nextToken();
          }
          if (country == null && variant == null) {
            return new Locale(language);
          } else if (variant == null) {
            return new Locale(language, country);
          } else {
            return new Locale(language, country, variant);
          }
        }

@Override
        public void write(JsonWriter out, Locale value) throws IOException {
          out.value(value == null ? null : value.toString());
        }

private JsonElement tryBeginNesting(JsonReader in, JsonToken peeked) throws IOException {
          switch (peeked) {
            case BEGIN_ARRAY:
              in.beginArray();
              return new JsonArray();
            case BEGIN_OBJECT:
              in.beginObject();
              return new JsonObject();
            default:
              return null;
          }
        }

private JsonElement readTerminal(JsonReader in, JsonToken peeked) throws IOException {
          switch (peeked) {
            case STRING:
              return new JsonPrimitive(in.nextString());
            case NUMBER:
              String number = in.nextString();
              return new JsonPrimitive(new LazilyParsedNumber(number));
            case BOOLEAN:
              return new JsonPrimitive(in.nextBoolean());
            case NULL:
              in.nextNull();
              return JsonNull.INSTANCE;
            default:
              // When read(JsonReader) is called with JsonReader in invalid state
              throw new IllegalStateException("Unexpected token: " + peeked);
          }
        }

public static JsonElement parse(JsonReader reader) throws JsonParseException {
    boolean isEmpty = true;
    try {
      JsonToken unused = reader.peek();
      isEmpty = false;
      return TypeAdapters.JSON_ELEMENT.read(reader);
    } catch (EOFException e) {
      /*
       * For compatibility with JSON 1.5 and earlier, we return a JsonNull for
       * empty documents instead of throwing.
       */
      if (isEmpty) {
        return JsonNull.INSTANCE;
      }
      // The stream ended prematurely so it is likely a syntax error.
      throw new JsonSyntaxException(e);
    } catch (MalformedJsonException e) {
      throw new JsonSyntaxException(e);
    } catch (IOException e) {
      throw new JsonIOException(e);
    } catch (NumberFormatException e) {
      throw new JsonSyntaxException(e);
    }
  }

